      always @ (posedge clk__noc) begin
         if (reset_n_system) begin
            if (n_valid_reduc_in || n_valid_reduc_out || e_valid_reduc_in || e_valid_reduc_out || s_valid_reduc_in || s_valid_reduc_out || w_valid_reduc_in || w_valid_reduc_out) begin
